CREATE TABLE test (c1 INT PRIMARY KEY, c2 VARCHAR(3));
DESCRIBE test;
ALTER TABLE test MODIFY c2 CHAR(10);
DESCRIBE test;
ALTER TABLE test ADD c3 int;
DESCRIBE test;
ALTER TABLE test DROP COLUMN c3;
DESCRIBE test;
CREATE INDEX test_index ON test (c1, c2);
SELECT OWNER,INDEX_NAME,INDEX_TYPE,TABLE_OWNER,TABLE_NAME FROM ALL_INDEXES WHERE table_name='TEST'
SELECT * FROM USER_IND_COLUMNS WHERE table_name='TEST'
DROP INDEX test_index;
DROP TABLE test;
CREATE TABLE t1(c1 INT PRIMARY KEY, c2 INT);
SELECT * FROM t1;
INSERT INTO t1 VALUES(1,1);
SELECT * FROM t1;
INSERT INTO (SELECT * FROM t1) VALUES(2,2);
SELECT * FROM t1;
INSERT INTO t1 VALUES(3,3) RETURNING c1;
SELECT * FROM t1;
DELETE FROM t1 WHERE c1 = 2;
SELECT * FROM t1;
UPDATE t1 SET t1.c2 = 100 WHERE t1.c1 = 1;
SELECT * FROM t1;
UPDATE (SELECT * FROM t1) v SET v.c2 = 300 WHERE v.c1 = 3;
SELECT * FROM t1;
CREATE TABLE t2 (id INT, name VARCHAR(50), num INT);
INSERT INTO t2 VALUES(1,'a',100),(2,'b',200),(3,'a',50);
SELECT * FROM t2;
SELECT name FROM t2;
SELECT DISTINCT name FROM t2;
SELECT id, name, num FROM t2 WHERE name = 'a';
CREATE TABLE t_insert(
id number NOT NULL PRIMARY KEY,
name varchar(10) NOT NULL,
value number NOT NULL,
gmt_create date NOT NULL DEFAULT sysdate
);
INSERT INTO t_insert(id, name, value, gmt_create) VALUES(1,'CN',10001, sysdate),(2,'US',10002, sysdate),(3,'EN',10003, sysdate);
SELECT * FROM t_insert;
INSERT INTO t_insert(id, name, value) VALUES(4,'JP',10004);
COMMIT;
SELECT * FROM t_insert;
INSERT INTO t_insert(id, name, value) VALUES(5,'FR',10005),(6,'RU',10006);
SELECT * FROM t_insert;
ROLLBACK;
SELECT * FROM t_insert;
