1. 进入数据源页面，点击数据源【DMDB for MySQL】的整库同步按钮
2. 新建DMDB for MySQL任务
3. 输入sql后点击保存：
--创建测试表 test_tab
create table test_tab (id int primary key, name varchar(30));
--创建有参数存储过程 p_test
create or replace procedure p_test(i in int)
as j int;
begin
for j in 1 ..i loop
insert into test_tab values(j,'p_test'||j);
end loop;
end;
TRUNCATE TABLE test_tab;
p_test(3);
--对表 test_tab 进行查询
select * from test_tab;
--删除存储过程
drop procedure p_test;
--创建无参数存储过程 p_test2
create or replace procedure p_test2 as j int;
begin
for j in 10 ..13 loop
insert into test_tab values(j,'p_test2:'||j);
end loop;
end;
p_test2;
--对表 test_tab 进行查询
select * from test_tab;
--删除存储过程
drop procedure p_test2;
