CREATE TABLE primary_table (id NUMBER PRIMARY KEY, names VARCHAR(100) NOT NULL, foreign_col NUMBER);
CREATE TABLE reference_table (id NUMBER PRIMARY key, comments VARCHAR2(100) NOT NULL);
ALTER TABLE primary_table ADD CONSTRAINT cons_fk1 FOREIGN KEY(foreign_col) REFERENCES reference_table(id);
SELECT ALL_CONS_COLUMNS.TABLE_NAME, ALL_CONS_COLUMNS.CONSTRAINT_NAME, ALL_CONS_COLUMNS.OWNER
FROM SYSCONS, SYSOBJECTS, ALL_CONS_COLUMNS
WHERE SYSCONS.id=SYSOBJECTS.id
--'F'代表外键，'P'代表主键，'U'唯一索引
AND SYSCONS.TYPE$='F'
AND SYSOBJECTS.name=ALL_CONS_COLUMNS.CONSTRAINT_NAME
-- 下面的用户名改成你的用户名，不加的话系统表中的约束也会查出来
AND ALL_CONS_COLUMNS.OWNER='用户名';
ALTER TABLE primary_table drop CONSTRAINT cons_fk1;
